import os
import hashlib
import hmac

def _get_stored_admin_hash() -> bytes:
    """
    Retrieve the SHA-256 hash of the admin password from the environment.
    The environment variable ADMIN_PASSWORD_HASH should contain the hex digest.
    """
    hex_hash = os.getenv("ADMIN_PASSWORD_HASH")
    if not hex_hash:
        raise RuntimeError("Admin password hash not configured in environment variable ADMIN_PASSWORD_HASH")
    try:
        return bytes.fromhex(hex_hash.strip())
    except ValueError as exc:
        raise RuntimeError("Invalid hex value for ADMIN_PASSWORD_HASH") from exc

def _hash_password(password: str) -> bytes:
    """
    Compute the SHA-256 hash of the given password string.
    """
    return hashlib.sha256(password.encode("utf-8")).digest()

def checkAdminPassword(password) -> bool:
    """
    Verify that the supplied password matches the stored admin password.

    The function performs a constant‑time comparison to mitigate timing attacks.
    It returns True only when the password is a string and its SHA‑256 hash
    equals the pre‑configured admin password hash.

    Raises:
        RuntimeError: If the admin password hash is not configured correctly.
    """
    if not isinstance(password, str):
        return False

    try:
        stored_hash = _get_stored_admin_hash()
    except RuntimeError:
        # In a production setting you might log this error securely.
        return False

    candidate_hash = _hash_password(password)
    return hmac.compare_digest(candidate_hash, stored_hash)

