import json
from typing import Any

def makePickleData(payload: Any) -> bytes:
    """
    Serialize the given payload object using JSON and return the resulting bytes.
    This avoids the security risks associated with pickle deserialization.
    """
    try:
        # Use the object's __dict__ for custom objects, falling back to the default JSON encoder.
        json_str = json.dumps(payload, default=lambda o: getattr(o, "__dict__", str(o)))
    except (TypeError, ValueError) as exc:
        raise ValueError("Payload is not JSON-serializable") from exc

    return json_str.encode("utf-8")

