import io


class _RestrictedUnpickler(pickle.Unpickler):
    """Unpickler that only allows safe built‑in types."""

    _SAFE_BUILTINS = {
        "list",
        "dict",
        "set",
        "tuple",
        "str",
        "int",
        "float",
        "bool",
        "bytes",
    }

    def find_class(self, module, name):
        if module == "builtins" and name in self._SAFE_BUILTINS:
            return getattr(__builtins__, name)
        raise pickle.UnpicklingError(f"Attempted to unpickle unsafe object: {module}.{name}")


def _safe_loads(data: bytes):
    """Deserialize `data` using the restricted unpickler."""
    return _RestrictedUnpickler(io.BytesIO(data)).load()


def getPickleData(pickled):
    """
    Return deserialized data from a pickle payload.

    The function accepts either ``bytes`` or a ``str`` (which will be
    UTF‑8 encoded) and safely deserialises it, allowing only a limited set
    of built‑in container and primitive types.
    """
    if isinstance(pickled, str):
        # Encode strings to bytes; UTF‑8 is a sensible default.
        pickled = pickled.encode("utf-8")
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled must be bytes or str")
    return _safe_loads(pickled)

